export const getUpdateApiKeyUrl = (keyId: number,) => {




  return `/api/keys/${keyId}`
}

/**
 * @summary Update webhook URL for an API key
 */
export const updateApiKey = async (keyId: number,
    updateApiKeyInput: UpdateApiKeyInput, options?: RequestInit): Promise<ApiKey> => {

  return customFetch<ApiKey>(getUpdateApiKeyUrl(keyId),
  {
    ...options,
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(
      updateApiKeyInput,)
  }
);}




export const getUpdateApiKeyMutationOptions = <TError = ErrorType<ErrorResponse>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof updateApiKey>>, TError,{keyId: number;data: BodyType<UpdateApiKeyInput>}, TContext>, request?: SecondParameter<typeof customFetch>}
): UseMutationOptions<Awaited<ReturnType<typeof updateApiKey>>, TError,{keyId: number;data: BodyType<UpdateApiKeyInput>}, TContext> => {

const mutationKey = ['updateApiKey'];
const {mutation: mutationOptions, request: requestOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }, request: undefined};




      const mutationFn: MutationFunction<Awaited<ReturnType<typeof updateApiKey>>, {keyId: number;data: BodyType<UpdateApiKeyInput>}> = (props) => {
          const {keyId,data} = props ?? {};

          return  updateApiKey(keyId,data,requestOptions)
        }






  return  { mutationFn, ...mutationOptions }}

    export type UpdateApiKeyMutationResult = NonNullable<Awaited<ReturnType<typeof updateApiKey>>>
    export type UpdateApiKeyMutationBody = BodyType<UpdateApiKeyInput>
    export type UpdateApiKeyMutationError = ErrorType<ErrorResponse>

    /**
 * @summary Update webhook URL for an API key
 */
export const useUpdateApiKey = <TError = ErrorType<ErrorResponse>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof updateApiKey>>, TError,{keyId: number;data: BodyType<UpdateApiKeyInput>}, TContext>, request?: SecondParameter<typeof customFetch>}
 ): UseMutationResult<
        Awaited<ReturnType<typeof updateApiKey>>,
        TError,
        {keyId: number;data: BodyType<UpdateApiKeyInput>},
        TContext
      > => {
      return useMutation(getUpdateApiKeyMutationOptions(options));
    }

export const getTestGatewayUrl = () => {




  return `/api/gateway/test`
}

/**
 * @summary Send a test SMS to verify gateway is working
 */
export const testGateway = async (gatewayTestInput: GatewayTestInput, options?: RequestInit): Promise<GatewayTestResult> => {

  return customFetch<GatewayTestResult>(getTestGatewayUrl(),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(
      gatewayTestInput,)
  }
);}




export const getTestGatewayMutationOptions = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof testGateway>>, TError,{data: BodyType<GatewayTestInput>}, TContext>, request?: SecondParameter<typeof customFetch>}
): UseMutationOptions<Awaited<ReturnType<typeof testGateway>>, TError,{data: BodyType<GatewayTestInput>}, TContext> => {

const mutationKey = ['testGateway'];
const {mutation: mutationOptions, request: requestOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }, request: undefined};




      const mutationFn: MutationFunction<Awaited<ReturnType<typeof testGateway>>, {data: BodyType<GatewayTestInput>}> = (props) => {
          const {data} = props ?? {};

          return  testGateway(data,requestOptions)
        }






  return  { mutationFn, ...mutationOptions }}

    export type TestGatewayMutationResult = NonNullable<Awaited<ReturnType<typeof testGateway>>>
    export type TestGatewayMutationBody = BodyType<GatewayTestInput>
    export type TestGatewayMutationError = ErrorType<unknown>

    /**
 * @summary Send a test SMS to verify gateway is working
 */
export const useTestGateway = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof testGateway>>, TError,{data: BodyType<GatewayTestInput>}, TContext>, request?: SecondParameter<typeof customFetch>}
 ): UseMutationResult<
        Awaited<ReturnType<typeof testGateway>>,
        TError,
        {data: BodyType<GatewayTestInput>},
        TContext
      > => {
      return useMutation(getTestGatewayMutationOptions(options));
    }

